// Validate harness request and build a safe Stop And Error object.
// Allowed test cases only — do not accept arbitrary error categories.
const body = $input.first().json.body ?? $input.first().json;

const ALLOWED_TEST_CASES = [
  'gemini_timeout',
  'classification_validation_failure',
  'contract_violation',
  'orphan_unhandled_exception',
];
const CAPTURE_ID_RE = /^SB-\d{8}-\d{4}$/;

const testCase = body.test_case;
if (!ALLOWED_TEST_CASES.includes(testCase)) {
  throw new Error(`Unknown test_case: ${JSON.stringify(testCase)}. Allowed: ${ALLOWED_TEST_CASES.join(', ')}`);
}

const ERROR_TEMPLATES = {
  gemini_timeout: {
    disposition: 'retryable',
    error_type: 'gemini_timeout',
    reason_type: 'workflow_error',
    stage: 'gemini',
  },
  classification_validation_failure: {
    disposition: 'retryable',
    error_type: 'classification_validation_failure',
    reason_type: 'workflow_error',
    stage: 'classification_validation',
  },
  contract_violation: {
    disposition: 'terminal',
    error_type: 'contract_violation',
    reason_type: 'workflow_error',
    stage: 'workflow_unknown',
  },
  orphan_unhandled_exception: null,
};

let errorObject;

if (testCase === 'orphan_unhandled_exception') {
  // Deliberately throw without capture correlation to test orphan path
  errorObject = { test_case: 'orphan_unhandled_exception' };
} else {
  const captureId = body.capture_id;
  const deliveryAttempt = body.delivery_attempt;

  if (!captureId || !CAPTURE_ID_RE.test(captureId)) {
    throw new Error('capture_id is required for correlated test cases and must match ^SB-\\d{8}-\\d{4}$');
  }
  if (!Number.isInteger(deliveryAttempt) || deliveryAttempt < 1) {
    throw new Error('delivery_attempt must be an integer >= 1 for correlated test cases');
  }

  errorObject = {
    capture_id: captureId,
    delivery_attempt: deliveryAttempt,
    ...ERROR_TEMPLATES[testCase],
  };
}

return [{ json: { error_object: errorObject } }];
